css:
.loader {color: var(--loader-color, #2563eb);
  --loader-secondary-color: #38bdf8;
  --loader-bg: #ffffff;
  width: 20px;
  aspect-ratio: 1;
  border-radius: 50%;
  background: currentColor;
  box-shadow: 0 0 0 0 color-mix(in srgb, currentColor 25%, transparent);
  animation: l2 1.5s infinite linear;
  position: relative;
}.loader:before,.loader:after {content: "";
  position: absolute;
  inset: 0;
  border-radius: inherit;
  box-shadow: 0 0 0 0 color-mix(in srgb, currentColor 25%, transparent);
  animation: inherit;
  animation-delay: -0.5s;
}.loader:before {animation-delay: -1s;
}@keyframes l2 {100% {box-shadow: 0 0 0 40px #0000}}
